import React, { useState } from "react";

// Available fraction blocks
const FRACTIONS = [
  { numerator: 1, denominator: 2, color: "#60A5FA", label: "1/2" },
  { numerator: 1, denominator: 3, color: "#34D399", label: "1/3" },
  { numerator: 1, denominator: 4, color: "#F87171", label: "1/4" },
  { numerator: 1, denominator: 6, color: "#FBBF24", label: "1/6" },
  { numerator: 1, denominator: 8, color: "#A78BFA", label: "1/8" },
];

// --- COMPONENT: FREE PLAY (The original builder) ---
function FreePlay() {
  const [rows, setRows] = useState([[], [], []]);

  const handleDragStart = (e, fraction) => e.dataTransfer.setData("fraction", JSON.stringify(fraction));
  const handleDragOver = (e) => e.preventDefault();

  const handleDrop = (e, rowIndex) => {
    e.preventDefault();
    const fractionData = e.dataTransfer.getData("fraction");
    if (fractionData) {
      const fraction = JSON.parse(fractionData);
      const currentTotal = rows[rowIndex].reduce((sum, f) => sum + f.numerator / f.denominator, 0);
      const incomingValue = fraction.numerator / fraction.denominator;

      if (currentTotal + incomingValue <= 1.01) {
        const newRows = [...rows];
        newRows[rowIndex].push({ ...fraction, id: Math.random() });
        setRows(newRows);
      } else {
        alert("Oops! That piece is too big to fit in this row!");
      }
    }
  };

  const removeBlock = (rowIndex, blockIndex) => {
    const newRows = [...rows];
    newRows[rowIndex].splice(blockIndex, 1);
    setRows(newRows);
  };

  return (
    <div style={{ backgroundColor: "white", padding: "20px", borderRadius: "12px", boxShadow: "0 10px 15px rgba(0,0,0,0.05)" }}>
      <p style={{ textAlign: "center", fontSize: "18px", color: "#4B5563" }}>
        Drag the colorful blocks into the empty rows. Can you make two rows exactly the same length?
      </p>

      {/* Toolbox */}
      <div style={{ display: "flex", justifyContent: "center", gap: "10px", margin: "20px 0", flexWrap: "wrap" }}>
        {FRACTIONS.map((frac, index) => (
          <div key={index} draggable onDragStart={(e) => handleDragStart(e, frac)}
            style={{ width: "80px", height: "50px", backgroundColor: frac.color, display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontWeight: "bold", fontSize: "20px", borderRadius: "8px", cursor: "grab", boxShadow: "0 4px 6px rgba(0,0,0,0.1)" }}>
            {frac.label}
          </div>
        ))}
      </div>

      <div style={{ marginBottom: "20px" }}>
        <strong style={{ color: "#374151" }}>This is 1 Whole:</strong>
        <div style={{ width: "100%", height: "50px", backgroundColor: "#9CA3AF", borderRadius: "8px", display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontWeight: "bold", fontSize: "20px", marginTop: "5px" }}>1 Whole</div>
      </div>

      {rows.map((row, rowIndex) => (
        <div key={rowIndex} style={{ marginBottom: "15px" }}>
          <strong style={{ color: "#374151" }}>Row {rowIndex + 1}:</strong>
          <div onDragOver={handleDragOver} onDrop={(e) => handleDrop(e, rowIndex)}
            style={{ width: "100%", height: "60px", backgroundColor: "#F3F4F6", borderRadius: "8px", border: "3px dashed #D1D5DB", display: "flex", marginTop: "5px", overflow: "hidden", position: "relative" }}>
            {row.length === 0 && <span style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%, -50%)", color: "#9CA3AF" }}>Drag blocks here!</span>}
            {row.map((block, blockIndex) => (
              <div key={block.id} onClick={() => removeBlock(rowIndex, blockIndex)} title="Click to remove"
                style={{ width: `${(block.numerator / block.denominator) * 100}%`, height: "100%", backgroundColor: block.color, display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontWeight: "bold", fontSize: "18px", borderRight: "2px solid rgba(0,0,0,0.2)", cursor: "pointer", boxSizing: "border-box" }}>
                {block.label}
              </div>
            ))}
          </div>
        </div>
      ))}
      <div style={{ textAlign: "center", marginTop: "20px" }}>
        <button onClick={() => setRows([[], [], []])} style={{ padding: "10px 20px", backgroundColor: "#EF4444", color: "white", border: "none", borderRadius: "8px", fontSize: "16px", cursor: "pointer", fontWeight: "bold" }}>🗑️ Clear Board</button>
      </div>
    </div>
  );
}

// --- COMPONENT: CHALLENGE MODE ---
const CHALLENGES = [
  { id: 1, text: "Can you make 1/2 using only Red 1/4 blocks?", target: 0.5 },
  { id: 2, text: "Make 1 Whole using only Green 1/3 blocks!", target: 1.0 },
  { id: 3, text: "Can you make 1/2 using only Purple 1/8 blocks?", target: 0.5 },
  { id: 4, text: "Mix and match! Make 1 Whole using different sized blocks.", target: 1.0 }
];

function ChallengeMode() {
  const [currentLevel, setCurrentLevel] = useState(0);
  const [row, setRow] = useState([]);
  const [isSuccess, setIsSuccess] = useState(false);

  const activeChallenge = CHALLENGES[currentLevel];

  const handleDragStart = (e, fraction) => e.dataTransfer.setData("fraction", JSON.stringify(fraction));
  const handleDragOver = (e) => e.preventDefault();

  const handleDrop = (e) => {
    e.preventDefault();
    if (isSuccess) return; // Stop adding if already won

    const fractionData = e.dataTransfer.getData("fraction");
    if (fractionData) {
      const fraction = JSON.parse(fractionData);
      const currentTotal = row.reduce((sum, f) => sum + f.numerator / f.denominator, 0);
      const incomingValue = fraction.numerator / fraction.denominator;

      if (currentTotal + incomingValue <= 1.01) {
        const newRow = [...row, { ...fraction, id: Math.random() }];
        setRow(newRow);
        checkAnswer(newRow);
      } else {
        alert("Oops! That's too big!");
      }
    }
  };

  const removeBlock = (blockIndex) => {
    if (isSuccess) return;
    const newRow = [...row];
    newRow.splice(blockIndex, 1);
    setRow(newRow);
    checkAnswer(newRow);
  };

  const checkAnswer = (currentRow) => {
    const total = currentRow.reduce((sum, f) => sum + f.numerator / f.denominator, 0);
    // Use Math.abs for floating point comparison
    if (Math.abs(total - activeChallenge.target) < 0.01) {
      setIsSuccess(true);
    }
  };

  const nextChallenge = () => {
    setRow([]);
    setIsSuccess(false);
    setCurrentLevel((prev) => (prev + 1) % CHALLENGES.length);
  };

  return (
    <div style={{ backgroundColor: "white", padding: "20px", borderRadius: "12px", boxShadow: "0 10px 15px rgba(0,0,0,0.05)", textAlign: "center" }}>
      <h2 style={{ color: "#D97706" }}>Level {currentLevel + 1}: {activeChallenge.text}</h2>

      {/* Toolbox */}
      <div style={{ display: "flex", justifyContent: "center", gap: "10px", margin: "20px 0", flexWrap: "wrap" }}>
        {FRACTIONS.map((frac, index) => (
          <div key={index} draggable onDragStart={(e) => handleDragStart(e, frac)}
            style={{ width: "80px", height: "50px", backgroundColor: frac.color, display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontWeight: "bold", fontSize: "20px", borderRadius: "8px", cursor: isSuccess ? "not-allowed" : "grab", opacity: isSuccess ? 0.5 : 1 }}>
            {frac.label}
          </div>
        ))}
      </div>

      {/* Target Reference Line (Visual hint for the kid) */}
      <div style={{ marginBottom: "5px", width: "100%", height: "20px", display: "flex" }}>
         <div style={{ width: `${activeChallenge.target * 100}%`, borderBottom: "4px solid #10B981", margin: "0 auto 0 0" }}>
            <span style={{ fontSize: "14px", color: "#10B981", fontWeight: "bold" }}>Target Goal</span>
         </div>
      </div>

      {/* Challenge Drop Zone */}
      <div onDragOver={handleDragOver} onDrop={handleDrop}
        style={{ width: "100%", height: "80px", backgroundColor: isSuccess ? "#D1FAE5" : "#F3F4F6", borderRadius: "8px", border: isSuccess ? "3px solid #10B981" : "3px dashed #D1D5DB", display: "flex", overflow: "hidden", position: "relative", transition: "background-color 0.3s" }}>
        {row.length === 0 && <span style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%, -50%)", color: "#9CA3AF" }}>Build your answer here!</span>}

        {row.map((block, blockIndex) => (
          <div key={block.id} onClick={() => removeBlock(blockIndex)}
            style={{ width: `${(block.numerator / block.denominator) * 100}%`, height: "100%", backgroundColor: block.color, display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontWeight: "bold", fontSize: "20px", borderRight: "2px solid rgba(0,0,0,0.2)", cursor: "pointer", boxSizing: "border-box" }}>
            {block.label}
          </div>
        ))}
      </div>

      {isSuccess && (
        <div style={{ marginTop: "20px", animation: "bounce 1s" }}>
          <h3 style={{ color: "#10B981", fontSize: "24px" }}>🎉 You did it! Great job! 🎉</h3>
          <button onClick={nextChallenge} style={{ padding: "12px 24px", backgroundColor: "#3B82F6", color: "white", border: "none", borderRadius: "8px", fontSize: "18px", cursor: "pointer", fontWeight: "bold", marginTop: "10px" }}>
            Next Challenge ➡️
          </button>
        </div>
      )}
    </div>
  );
}

