      <h1 style={{ textAlign: "center", color: "#1E3A8A", fontSize: "36px", marginBottom: "10px" }}>🍕 Fraction Fun Builder! 🍕</h1>

      {/* Navigation Menu */}
      <div style={{ display: "flex", justifyContent: "center", gap: "20px", marginBottom: "30px" }}>
        <button 
          onClick={() => setActiveTab("free")}
          style={{ padding: "12px 24px", fontSize: "18px", fontWeight: "bold", cursor: "pointer", borderRadius: "30px", border: "none", backgroundColor: activeTab === "free" ? "#3B82F6" : "#E5E7EB", color: activeTab === "free" ? "white" : "#4B5563", boxShadow: activeTab === "free" ? "0 4px 6px rgba(59, 130, 246, 0.3)" : "none", transition: "all 0.2s" }}
        >
          🎈 Free Play
        </button>
        <button 
          onClick={() => setActiveTab("challenge")}
          style={{ padding: "12px 24px", fontSize: "18px", fontWeight: "bold", cursor: "pointer", borderRadius: "30px", border: "none", backgroundColor: activeTab === "challenge" ? "#D97706" : "#E5E7EB", color: activeTab === "challenge" ? "white" : "#4B5563", boxShadow: activeTab === "challenge" ? "0 4px 6px rgba(217, 119, 6, 0.3)" : "none", transition: "all 0.2s" }}
        >
          🏆 Challenges
        </button>
      </div>

      {/* Show the selected page */}
      {activeTab === "free" ? <FreePlay /> : <ChallengeMode />}
    </div>
  );
}
